const TRENDING_KEYWORDS = ['GPT-', 'Claude ', 'Gemini ', 'Llama '];

function sha256Hex(str) {
  function rrot(x, n) { return (x >>> n) | (x << (32 - n)); }
  const K = [0x428a2f98,0x71374491,0xb5c0fbcf,0xe9b5dba5,0x3956c25b,0x59f111f1,0x923f82a4,0xab1c5ed5,0xd807aa98,0x12835b01,0x243185be,0x550c7dc3,0x72be5d74,0x80deb1fe,0x9bdc06a7,0xc19bf174,0xe49b69c1,0xefbe4786,0x0fc19dc6,0x240ca1cc,0x2de92c6f,0x4a7484aa,0x5cb0a9dc,0x76f988da,0x983e5152,0xa831c66d,0xb00327c8,0xbf597fc7,0xc6e00bf3,0xd5a79147,0x06ca6351,0x14292967,0x27b70a85,0x2e1b2138,0x4d2c6dfc,0x53380d13,0x650a7354,0x766a0abb,0x81c2c92e,0x92722c85,0xa2bfe8a1,0xa81a664b,0xc24b8b70,0xc76c51a3,0xd192e819,0xd6990624,0xf40e3585,0x106aa070,0x19a4c116,0x1e376c08,0x2748774c,0x34b0bcb5,0x391c0cb3,0x4ed8aa4a,0x5b9cca4f,0x682e6ff3,0x748f82ee,0x78a5636f,0x84c87814,0x8cc70208,0x90befffa,0xa4506ceb,0xbef9a3f7,0xc67178f2];
  let H = [0x6a09e667,0xbb67ae85,0x3c6ef372,0xa54ff53a,0x510e527f,0x9b05688c,0x1f83d9ab,0x5be0cd19];
  const bytes = [];
  const utf8 = unescape(encodeURIComponent(str));
  for (let i = 0; i < utf8.length; i++) bytes.push(utf8.charCodeAt(i));
  const bitLen = bytes.length * 8;
  bytes.push(0x80);
  while (bytes.length % 64 !== 56) bytes.push(0);
  for (let i = 7; i >= 0; i--) bytes.push((bitLen / Math.pow(2, i * 8)) & 0xff);
  const w = new Array(64);
  for (let chunk = 0; chunk < bytes.length; chunk += 64) {
    for (let i = 0; i < 16; i++) {
      w[i] = (bytes[chunk + i*4] << 24) | (bytes[chunk + i*4+1] << 16) | (bytes[chunk + i*4+2] << 8) | (bytes[chunk + i*4+3]);
    }
    for (let i = 16; i < 64; i++) {
      const s0 = rrot(w[i-15],7) ^ rrot(w[i-15],18) ^ (w[i-15] >>> 3);
      const s1 = rrot(w[i-2],17) ^ rrot(w[i-2],19) ^ (w[i-2] >>> 10);
      w[i] = (w[i-16] + s0 + w[i-7] + s1) | 0;
    }
    let [a,b,c,d,e,f,g,h] = H;
    for (let i = 0; i < 64; i++) {
      const S1 = rrot(e,6) ^ rrot(e,11) ^ rrot(e,25);
      const ch = (e & f) ^ (~e & g);
      const temp1 = (h + S1 + ch + K[i] + w[i]) | 0;
      const S0 = rrot(a,2) ^ rrot(a,13) ^ rrot(a,22);
      const maj = (a & b) ^ (a & c) ^ (b & c);
      const temp2 = (S0 + maj) | 0;
      h=g; g=f; f=e; e=(d+temp1)|0; d=c; c=b; b=a; a=(temp1+temp2)|0;
    }
    H = [H[0]+a|0, H[1]+b|0, H[2]+c|0, H[3]+d|0, H[4]+e|0, H[5]+f|0, H[6]+g|0, H[7]+h|0];
  }
  return H.map((x) => (x >>> 0).toString(16).padStart(8, '0')).join('');
}

const results = [];
for (const item of items) {
  const link = item.json.link;
  const title = item.json.title ?? '';
  const snippet = (item.json.contentSnippet ?? item.json.summary ?? item.json.description ?? '').replace(/<[^>]+>/g, '');
  const pubDate = item.json.pubDate ? new Date(item.json.pubDate) : new Date();
  const dateStr = Number.isNaN(pubDate.valueOf()) ? new Date().toISOString().slice(0, 10) : pubDate.toISOString().slice(0, 10);
  const slug = `${dateStr}-${sha256Hex(link).slice(0, 8)}`;
  const trending = TRENDING_KEYWORDS.some((kw) => title.includes(kw));
  results.push({ json: { lab: 'huggingface', slug, title, link, snippet, trending } });
}
return results;

return items.map((item) => {
  const MAX = 280;
  let text = item.json.snippet ?? '';
  if (text.length > MAX) {
    const cut = text.slice(0, MAX);
    const lastPeriod = cut.lastIndexOf('. ');
    text = (lastPeriod > 100 ? cut.slice(0, lastPeriod + 1) : cut) + '…';
  }
  return { json: { ...item.json, descriptionEn: text } };
});

return items.map((item) => ({
  json: {
    ...item.json,
    titleEs: item.json.title,
    descriptionEs: item.json.descriptionEn,
    translationOutdated: true,
  },
}));

const src = $('Code: ES (fallback, sin traducción automática)').item.json;
const masterSha = $json.object.sha;
const today = new Date().toISOString().slice(0, 10);

const B64_CHARS = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/';
function base64EncodeUtf8(str) {
  const utf8 = unescape(encodeURIComponent(str));
  let out = '';
  let i = 0;
  for (; i + 2 < utf8.length; i += 3) {
    const n = (utf8.charCodeAt(i) << 16) | (utf8.charCodeAt(i+1) << 8) | utf8.charCodeAt(i+2);
    out += B64_CHARS[(n >> 18) & 63] + B64_CHARS[(n >> 12) & 63] + B64_CHARS[(n >> 6) & 63] + B64_CHARS[n & 63];
  }
  const rem = utf8.length - i;
  if (rem === 1) {
    const n = utf8.charCodeAt(i) << 16;
    out += B64_CHARS[(n >> 18) & 63] + B64_CHARS[(n >> 12) & 63] + '==';
  } else if (rem === 2) {
    const n = (utf8.charCodeAt(i) << 16) | (utf8.charCodeAt(i+1) << 8);
    out += B64_CHARS[(n >> 18) & 63] + B64_CHARS[(n >> 12) & 63] + B64_CHARS[(n >> 6) & 63] + '=';
  }
  return out;
}

function yamlEscape(value) {
  return String(value).replace(/\\/g, '\\\\').replace(/"/g, '\\"');
}

function buildFrontmatter({ title, description, translationKey, sourceUpdated, publishedAt, sourceUrl, lab, trending, lang, translationOutdated }) {
  const lines = [
    '---',
    `title: "${yamlEscape(title)}"`,
    `description: "${yamlEscape(description)}"`,
    `translationKey: ${translationKey}`,
    `sourceUpdated: ${sourceUpdated}`,
    `publishedAt: ${publishedAt}`,
    `sourceUrl: "${yamlEscape(sourceUrl)}"`,
    `lab: ${lab}`,
    `trending: ${trending}`,
    'reviewed: false',
    `lang: ${lang}`,
  ];
  if (translationOutdated) lines.push('translationOutdated: true');
  lines.push('---', '');
  return lines.join('\n');
}

const enContent = buildFrontmatter({
  title: src.title,
  description: src.descriptionEn,
  translationKey: src.slug,
  sourceUpdated: today,
  publishedAt: today,
  sourceUrl: src.link,
  lab: src.lab,
  trending: src.trending,
  lang: 'en',
});

const esContent = buildFrontmatter({
  title: src.titleEs,
  description: src.descriptionEs,
  translationKey: src.slug,
  sourceUpdated: today,
  publishedAt: today,
  sourceUrl: src.link,
  lab: src.lab,
  trending: src.trending,
  lang: 'es',
  translationOutdated: src.translationOutdated,
});

return [{
  json: {
    slug: src.slug,
    title: src.title,
    link: src.link,
    lab: src.lab,
    trending: src.trending,
    masterSha,
    contentEnBase64: base64EncodeUtf8(enContent),
    contentEsBase64: base64EncodeUtf8(esContent),
  },
}];
